import struct
import os

def read_file(filename):
    with open(filename, 'rb') as f:
        return bytearray(f.read())

def write_file(filename, data):
    with open(filename, 'wb') as f:
        f.write(data)

def find_box(data, box_type):
    """Find a box of given type in MP4 data"""
    i = 0
    while i < len(data) - 8:
        size = struct.unpack('>I', data[i:i+4])[0]
        if size == 0:
            size = len(data) - i
        elif size == 1:
            # Extended size
            if i + 16 <= len(data):
                size = struct.unpack('>Q', data[i+8:i+16])[0]
        box = data[i+4:i+8].decode('ascii', errors='ignore')
        if box == box_type:
            return i, size
        i += size
    return -1, 0

def find_moov(data):
    return find_box(data, 'moov')

def find_trak(data):
    return find_box(data, 'trak')

def find_mdia(data):
    return find_box(data, 'mdia')

def find_minf(data):
    return find_box(data, 'minf')

def find_stbl(data):
    return find_box(data, 'stbl')

def find_stsz(data):
    return find_box(data, 'stsz')

