    return find_box(data, 'stsc')

def find_stco(data):
    return find_box(data, 'stco')

def find_stts(data):
    return find_box(data, 'stts')

def find_ctts(data):
    return find_box(data, 'ctts')

def find_mp4a(data):
    return find_box(data, 'mp4a')

def find_avc1(data):
    return find_box(data, 'avc1')

