    """Variant 1: Modify sample size table to trigger different allocation patterns"""
    print("Creating variant 1: Modified sample sizes")
    variant = bytearray(data)

    # Find stsz box (sample size)
    pos, size = find_stsz(variant)
    if pos > 0 and pos + 20 < len(variant):
        # stsz structure: size (4), type (4), version/flags (4), sample_size (4), sample_count (4)
        # Then array of sample sizes if sample_size == 0
        sample_size = struct.unpack('>I', variant[pos+12:pos+16])[0]
        sample_count = struct.unpack('>I', variant[pos+16:pos+20])[0]

        print(f"Found stsz at {pos}: sample_size={sample_size}, sample_count={sample_count}")

        if sample_size == 0 and sample_count > 0:
            # Modify first few sample sizes to be very large to trigger realloc
            for i in range(min(5, sample_count)):
                offset = pos + 20 + i * 4
                if offset + 4 <= len(variant):
                    # Set to large value (0x10000)
                    variant[offset:offset+4] = struct.pack('>I', 0x10000)

    return variant

def truncate_track_data(data):
    """Variant 2: Truncate track data to create incomplete parsing"""
    print("Creating variant 2: Truncated track data")
    variant = bytearray(data)

    # Find trak box
    pos, size = find_trak(variant)
    if pos > 0:
        # Truncate the trak box by reducing its size
        # But keep it valid enough to parse initially
        new_size = min(size, 5000)  # Make it much smaller
        if pos + 8 <= len(variant):
            variant[pos:pos+4] = struct.pack('>I', new_size)
            # Zero out the rest of the box
